try:
    from casos_banco_extra import CASOS_EXTRA as _EXTRA
    CASOS = CASOS + _EXTRA
except ImportError:
    pass


def get_casos(rama: str | None = None, dificultad: str | None = None) -> list[dict]:
    """Filtra casos por rama y/o dificultad."""
    result = CASOS
    if rama:
        result = [c for c in result if c["rama"] == rama]
    if dificultad:
        result = [c for c in result if c["dificultad"] == dificultad]
    return result


RAMAS = sorted({c["rama"] for c in CASOS})
SUBTEMAS = sorted({c["subtema"] for c in CASOS})
DIFICULTADES = ["básico", "intermedio", "avanzado"]
